/**
 * Inline VIETTOURS logo for embedding in PDF/DOCX exports.
 * Source: public/legacy.html:627 (data URI PNG).
 */

export const VTE_LOGO = "data:image/png;base64,";

/** Decode a base64 data URI into a Uint8Array for the docx ImageRun API. */
export function b64ToU8(b64: string): Uint8Array {
  const raw = (b64 || "").split(",")[1] || "";
  const bin = atob(raw);
  const u = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i += 1) u[i] = bin.charCodeAt(i);
  return u;
}

/** White Viettours logo (transparent bg) — for use on dark/teal headers. */
export const VTE_LOGO_WHITE = "data:image/png;base64,";
